void solve(int CASE)
{
	int n, q; cin >> n >> q;
	var g = vector<vector<int>>(n + 1);
	fa(i, 1, n) {
		int x, y; cin >> x >> y;
		if (x and y)g[i].pb(x), g[i].pb(y);
	}

	int timer = 0;
	var in = vector<ll>(n + 1);
	var out = vector<ll>(n + 1);
	var euler = vector<int>();
	var dp = Vec2<int>(n + 1, 21);  // 倍增父节点表
	var sum = Vec2<ll>(n + 1, 21);
	var dfs = [&](var dfs, int now, int fa)->void {
		euler.pb(now);
		in[now] = vs(euler);

		for (int to : g[now]) {
			if (to == fa)continue;
			dfs(dfs, to, now);
			euler.pb(now);
		}

		out[now] = vs(euler);

		dp[now][0] = fa;
		// now 想要往上跳到 fa，必须把当前的子树路径处理完
		sum[now][0] = out[now] - in[now] + 1; 
		};
	dfs(dfs, 1, 0);

	fa(p, 1, 20)fa(i, 1, n) {
		dp[i][p] = dp[dp[i][p - 1]][p - 1];
		sum[i][p] = sum[i][p - 1] + sum[dp[i][p - 1]][p - 1];
	}

	while (q--) {
		ll now, k; cin >> now >> k;
		// 这里使用贪心跳跃法
		fb(p, 20, 0) {
			if (k >= sum[now][p]) {
				k -= sum[now][p];
				now = dp[now][p];
			}
		}
		cout << euler[in[now] + k] << " ";
	}
	cout << endl;
	return;
}
